        public static Task<string> RunAsync(FaxCoreClient client, string sampleName)
        {
            EndpointSample sample;
            if (!Samples.TryGetValue(sampleName, out sample))
            {
                throw new ArgumentException("Unknown generated endpoint sample: " + sampleName);
            }

            if (sample.Destructive && !string.Equals(Environment.GetEnvironmentVariable("FAXCORE_CONFIRM_DESTRUCTIVE"), "true", StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("This sample changes or deletes data. Set FAXCORE_CONFIRM_DESTRUCTIVE=true to run it.");
            }

            return client.SendJsonAsync(sample.Method, sample.Path, sample.BodyJson);
        }

        private sealed class EndpointSample
        {
            public EndpointSample(string title, string method, string path, string bodyJsonBase64, bool destructive)
            {
                Title = title;
                Method = method;
                Path = path;
                BodyJson = Decode(bodyJsonBase64);
                Destructive = destructive;
            }

            public string Title { get; private set; }
            public string Method { get; private set; }
            public string Path { get; private set; }
            public string BodyJson { get; private set; }
            public bool Destructive { get; private set; }

            private static string Decode(string value)
            {
                return string.IsNullOrEmpty(value) ? string.Empty : Encoding.UTF8.GetString(Convert.FromBase64String(value));
            }
        }
